#[test]
fn phase2_all_languages_have_extractors() {
    // Verify that all Phase 2 extensions can find an extractor.
    let test_cases = vec![
        ("test.c", "c"),
        ("test.cpp", "cpp"),
        ("test.cs", "c_sharp"),
        ("test.rb", "ruby"),
        ("test.sh", "bash"),
        ("test.php", "php"),
        ("test.scala", "scala"),
        ("test.kt", "kotlin"),
        ("test.swift", "swift"),
        ("test.hs", "haskell"),
        ("test.ml", "ocaml"),
        ("test.lua", "lua"),
        ("test.ex", "elixir"),
        ("test.zig", "zig"),
    ];

    for (file, expected_lang) in &test_cases {
        let extractor = gnosis_polyglot::extractors::extractor_for_file(file);
        assert!(
            extractor.is_some(),
            "should find extractor for {} (expected language: {})",
            file,
            expected_lang
        );
        assert_eq!(
            extractor.unwrap().language_id(),
            *expected_lang,
            "wrong language for {}",
            file
        );
    }
}

