#[test]
fn orchestration_manifest_includes_all_functions() {
    let result = parse_and_extract_orchestration(PY_TYPED_PIPELINE, "typed_pipeline.py").unwrap();

    // Manifest should have plans for all functions.
    assert!(
        result.manifest.node_execution_plans.len() >= result.scan_result.topologies.len() * 2,
        "manifest should have at least entry+return plans per function (got {} plans for {} functions)",
        result.manifest.node_execution_plans.len(),
        result.scan_result.topologies.len()
    );

    // Every plan should have a valid kind.
    for plan in &result.manifest.node_execution_plans {
        assert!(
            ["entry", "call", "statement", "return", "join"].contains(&plan.kind.as_str()),
            "plan kind '{}' should be valid",
            plan.kind
        );
    }
}

#[test]
fn orchestration_typescript_has_bridge_labels_and_source_ranges() {
    let result = parse_and_extract_orchestration(TS_TYPED_HANDLER, "typed_handler.ts").unwrap();

    for topo in &result.scan_result.topologies {
        for node in &topo.topology.nodes {
            if node.labels.iter().any(|l| l.starts_with("PolyglotBridge")) {
                assert!(
                    node.properties.contains_key("source_start_byte"),
                    "PolyglotBridge node {} in {} should have source_start_byte",
                    node.id,
                    topo.function_name
                );
                assert!(
                    node.properties.contains_key("source_end_byte"),
                    "PolyglotBridge node {} in {} should have source_end_byte",
                    node.id,
                    topo.function_name
                );
            }
        }
    }
}

#[test]
fn all_five_languages_extract_signatures() {
    // Python
    let py = parse_and_extract(PY_TYPED_PIPELINE, "typed_pipeline.py").unwrap();
    assert!(
        py.topologies.iter().any(|t| !t.signature.params.is_empty()),
        "Python should extract params"
    );

    // Go
    let go = parse_and_extract(GO_API_HANDLER, "api_handler.go").unwrap();
    assert!(
        go.topologies.iter().any(|t| !t.signature.params.is_empty()),
        "Go should extract params"
    );
    assert!(
        go.topologies
            .iter()
            .any(|t| t.signature.return_type.is_some()),
        "Go should extract return types"
    );

    // TypeScript
    let ts = parse_and_extract(TS_TYPED_HANDLER, "typed_handler.ts").unwrap();
    assert!(
        ts.topologies
            .iter()
            .any(|t| !t.signature.params.is_empty() || t.signature.is_async),
        "TypeScript should extract params or async"
    );

    // Rust (using existing fixture)
    let rs = parse_and_extract(RS_SPAWN_NO_JOIN, "spawn_no_join.rs").unwrap();
    assert!(!rs.topologies.is_empty(), "Rust should extract functions");

    // Java (using existing fixture)
    let java = parse_and_extract(JAVA_CONN_LEAK, "connection_leak.java").unwrap();
    assert!(!java.topologies.is_empty(), "Java should extract functions");
}

#[test]
fn lean_basic_fixture_emits_proof_declarations_and_semantics() {
    let result = parse_and_extract(LEAN_BASIC, "Lean/Basic.lean").unwrap();
    assert_eq!(result.language, "lean");
    assert!(
        !result.topologies.is_empty(),
        "Lean should extract top-level declarations"
    );
    assert!(
        result
            .proof_declarations
            .iter()
            .any(|proof| proof.system == "lean4"),
        "Lean proof declarations should be emitted"
    );
    assert!(
        result
            .proof_declarations
            .iter()
            .any(|proof| proof.theorem.ends_with("add_zero")),
        "lemma proof declaration should be captured"
    );
    assert!(
        result
            .proof_declarations
            .iter()
            .any(|proof| proof.theorem.ends_with("prop_obligation")),
        "theorem proof declaration should be captured"
    );

    let double_fn = result
        .topologies
        .iter()
        .find(|topo| topo.function_name.ends_with("double"))
        .expect("should find double");
    assert_eq!(double_fn.signature.return_type.as_deref(), Some("Nat"));
    assert!(matches!(
        double_fn.semantic_contract.return_type,
        TopologyType::Json {
            schema: JsonSchema::Integer
        }
    ));

    let prop_fn = result
        .topologies
        .iter()
        .find(|topo| topo.function_name.ends_with("prop_obligation"))
        .expect("should find prop_obligation");
    assert!(matches!(
        prop_fn.semantic_contract.return_type,
        TopologyType::Opaque { ref language, ref name }
            if language == "lean" && name == "Prop"
    ));
    assert!(
        prop_fn
            .semantic_contract
            .obligations
            .iter()
            .any(|obligation| obligation.key == "lean_proposition_result"),
        "Lean proposition results should stay in proof space"
    );
    assert!(
        !double_fn.gg_source.trim().is_empty(),
        "Lean lowering should emit non-empty GG source"
    );
}

#[test]
fn lean_branchy_fixture_lowers_branch_structure() {
    let result = parse_and_extract(LEAN_BRANCHY, "Lean/Branchy.lean").unwrap();
    assert_eq!(result.language, "lean");
    assert!(
        result
            .topologies
            .iter()
            .any(|topo| topo.gg_source.contains("FORK") && topo.gg_source.contains("FOLD")),
        "branch-heavy Lean syntax should lower into fork/join topology"
    );

    let branchy = result
        .topologies
        .iter()
        .find(|topo| topo.function_name.ends_with("branchy"))
        .expect("should find branchy theorem");
    assert!(
        branchy
            .topology
            .nodes
            .iter()
            .any(|node| node.labels.contains(&"Branch".to_string())),
        "branchy proof should emit branch nodes"
    );
    assert!(
        branchy
            .topology
            .nodes
            .iter()
            .any(|node| node.labels.contains(&"Merge".to_string())),
        "branchy proof should emit merge nodes"
    );
}

#[test]
fn lean_multi_file_imports_are_resolved_locally() {
    let tmp = tempfile::tempdir().expect("create temp dir");
    let lean_root = tmp.path().join("Lean");
    std::fs::create_dir_all(&lean_root).expect("create Lean root");
    std::fs::write(lean_root.join("Entry.lean"), LEAN_MULTI_ENTRY).expect("write entry");
    std::fs::write(lean_root.join("Helper.lean"), LEAN_MULTI_HELPER).expect("write helper");

    let entry = lean_root.join("Entry.lean");
    let result = resolve_imports_recursive(&entry, DEFAULT_MAX_IMPORT_DEPTH)
        .expect("Lean multi-file import resolution should succeed");
    assert_eq!(result.language, "lean");
    assert!(
        result
            .topologies
            .iter()
            .any(|topo| topo.module_origin.ends_with("Entry.lean")),
        "entry topology should be tagged with module origin"
    );
    assert!(
        result
            .topologies
            .iter()
            .any(|topo| topo.module_origin.ends_with("Helper.lean")),
        "helper topology should be tagged with module origin"
    );
    assert!(
        result
            .external_imports
            .iter()
            .any(|import| import.module == "Mathlib"),
        "external Lean imports should be recorded"
    );

    let helper_origin = std::fs::canonicalize(lean_root.join("Helper.lean"))
        .expect("canonicalize helper path")
        .to_string_lossy()
        .to_string();
    let helper_topology = result
        .topologies
        .iter()
        .find(|topo| topo.module_origin == helper_origin)
        .expect("should find helper topology");
    assert!(
        helper_topology
            .topology
            .topology
            .nodes
            .iter()
            .any(|node| node.properties.get("module_origin") == Some(&helper_origin)),
        "module origin should be attached to Lean bridge entry nodes"
    );
    assert!(
        result
            .proof_declarations
            .iter()
            .any(|proof| proof.system == "lean4"),
        "Lean proof declarations should survive multi-file folding"
    );
}
